//! Body-politick signal bridge for Aeon Voting -> Thoth distributed inference.
//!
//! This module accepts aggregate Aeon Voting signal frames as observations,
//! converts them into semantic `PleromaticFrame`s, and emits a small admission
//! certificate. It does not treat polls, markets, phyles, or dashboards as
//! source authority.

use crate::pleromatic_frame::{PleromaticFrame, PleromaticMediaType};
use crate::scribal_standing_wave::{
    boundary_input_from_event_log, fold_scribal_audit_trace, scribal_audit_trace_sound,
    scribal_response_envelope_sound, use_claim, ScribalAuditTrace, ScribalResponseEnvelope,
    ScribalUseKind, CANONICAL_CERTIFICATE, CANONICAL_FAILURE_EVENT_LOG,
    SCRIBAL_STANDING_WAVE_THEOREM, THOTH_MECHANICAL_BRAIN_THEOREM,
};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

pub const BODY_POLITICK_SCHEMA: &str = "aeon.body-politick.signal.v1";
pub const BODY_POLITICK_OBSERVATION_THEOREM: &str =
    "Gnosis.BodyPolitickSignal.body_politick_signal_is_observation";
pub const BODY_POLITICK_NOT_AUTHORITY_THEOREM: &str =
    "Gnosis.BodyPolitickSignal.thoth_admission_preserves_non_authority";
pub const BODY_POLITICK_PRIVATE_BOUNDARY_THEOREM: &str =
    "Gnosis.BodyPolitickSignal.private_aggregate_blocks_member_reconstruction";
pub const BODY_PLEROMATIC_SCHEMA: &str = "aeon.body-pleromatic.signal.v1";
pub const BODY_PLEROMATIC_OBSERVATION_THEOREM: &str =
    "Gnosis.BodyPleromaticSignal.body_pleromatic_signal_is_observation";
pub const BODY_PLEROMATIC_NOT_AUTHORITY_THEOREM: &str =
    "Gnosis.BodyPleromaticSignal.thoth_admission_preserves_non_authority";
pub const BODY_PLEROMATIC_SHARED_UI_COVERAGE_THEOREM: &str =
    "Gnosis.BodyPleromaticSignal.shared_ui_sensor_radio_coverage";

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum BodyPolitickSourceClass {
    PublicMarket,
    PhylePrivateMarket,
    Poll,
    Panel,
    TreasuryPosition,
    EnergyMarket,
    AttentionMarket,
    LiquidDelegation,
    BehavioralPrior,
    GovernanceVote,
    ExternalOracle,
    SomaticBody,
    ThothBrain,
    BodyPolitick,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum BodyPleromaticSignalKind {
    Biometric,
    Activity,
    Environmental,
    Sleep,
    CvmGaze,
    ExternalReading,
    Contextual,
    MorphcastEmotion,
    DigitalPhenotype,
    RadioListen,
}

impl BodyPleromaticSignalKind {
    pub fn shared_ui_surface(&self) -> &'static str {
        match self {
            Self::Biometric => "shared-ui.sensor.biometric",
            Self::Activity => "shared-ui.sensor.activity",
            Self::Environmental => "shared-ui.sensor.environmental",
            Self::Sleep => "shared-ui.sensor.sleep",
            Self::CvmGaze => "shared-ui.sensor.cvm-gaze",
            Self::ExternalReading => "shared-ui.sensor.external-reading",
            Self::Contextual => "shared-ui.sensor.contextual",
            Self::MorphcastEmotion => "shared-ui.sensor.morphcast-emotion",
            Self::DigitalPhenotype => "shared-ui.sensor.digital-phenotype",
            Self::RadioListen => "shared-ui.radio.listen",
        }
    }
}

